mapper.select:
SELECT u.id, u.username, u.nickname, u.email, u.phone, u.avatar, u.dept_id, d.dept_name, u.status, u.is_builtin, u.created_at FROM sys_user u LEFT JOIN sys_dept d ON u.dept_id = d.id AND d.deleted = 0 WHERE u.deleted = 0
AND u.username LIKE CONCAT('%', #{q.username}, '%')
AND u.nickname LIKE CONCAT('%', #{q.nickname}, '%')
AND u.status = #{q.status}
AND u.dept_id = #{q.deptId}
ORDER BY u.created_at DESC
